const html = $input.item.json.body || $input.item.json.data || '';
const url = $('Trích xuất URL').first().json.url;

const title = (html.match(/<title[^>]*>([^<]+)<\/title>/i) || [])[1] || '';
const desc  = (html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']/i) || 
               html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']/i) || [])[1] || '';
const ogTitle = (html.match(/<meta[^>]+property=["']og:title["'][^>]+content=["']([^"']+)["']/i) || [])[1] || '';
const ogDesc  = (html.match(/<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']+)["']/i) || [])[1] || '';
const ogImage = (html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i) || [])[1] || '';

const cleanHtml = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 3000);

return [{ json: {
  url,
  title: ogTitle || title || '',
  description: ogDesc || desc || '',
  imageUrl: ogImage || '',
  content: cleanHtml,
  source: new URL(url).hostname
} }];

const item = $input.item.json;
const rawText = item.output || item.text || item.message || JSON.stringify(item);

const tagMatch     = rawText.match(/TAG:\s*([\w-]+)/);
const titleMatch   = rawText.match(/TITLE_VI:\s*(.+)/);
const excerptMatch = rawText.match(/EXCERPT:\s*(.+)/);
const socialMatch  = rawText.match(/SOCIAL_POST:\s*(.+)/);

const tag        = tagMatch     ? tagMatch[1].trim()     : 'ma';
const titleVi    = titleMatch   ? titleMatch[1].trim()   : $('Parse HTML → nội dung').first().json.title;
const excerpt    = excerptMatch ? excerptMatch[1].trim() : '';
const socialPost = socialMatch  ? socialMatch[1].trim()  : excerpt + '\n\n👉 sandboxstartup.vn/cases';

const cleanBody = rawText
  .replace(/TAG:\s*[\w-]+/g, '')
  .replace(/TITLE_VI:\s*.+/g, '')
  .replace(/EXCERPT:\s*.+/g, '')
  .replace(/SOCIAL_POST:\s*.+/g, '')
  .trim();

const now = new Date();
const slug = 'case-' + titleVi.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
  .replace(/đ/g,'d').replace(/[^a-z0-9]+/g,'-')
  .replace(/^-|-$/g,'').slice(0,55)
  + '-' + now.getFullYear()
  + (now.getMonth()+1).toString().padStart(2,'0')
  + now.getDate().toString().padStart(2,'0');

const dateStr  = now.toLocaleDateString('vi-VN', { day:'2-digit', month:'long', year:'numeric' });
const wordCount = cleanBody.split(' ').length;
const readTime = Math.ceil(wordCount / 180) + ' phút đọc';
const src = $('Parse HTML → nội dung').first().json;

return [{ json: {
  slug,
  title: titleVi,
  body: cleanBody,
  excerpt,
  tag,
  type: 'case',
  date: dateStr,
  readTime,
  wordCount,
  sourceUrl: src.url || '',
  imageUrl: src.imageUrl || '',
  status: 'published',
  views: '0',
  socialPost
} }];
